func planFieldValue(p *plan.Plan, field string) string {
	if p == nil {
		return ""
	}
	switch field {
	case "name":
		return p.Name
	case "slug":
		return p.Slug
	case "description":
		return p.Description
	case "currency":
		return p.Currency
	case "status":
		return string(p.Status)
	case "trial_days":
		if p.TrialDays == 0 {
			return ""
		}
		return strconv.Itoa(p.TrialDays)
	case "app_id":
		return p.AppID
	default:
		return ""
	}
}

func planAppIDValue(data PlanFormData) string {
	if data.Plan != nil && data.Plan.AppID != "" {
		return data.Plan.AppID
	}
	return data.AppID
}

func planPricingValue(p *plan.Plan) string {
	if p == nil || p.Pricing == nil {
		return ""
	}
	return strconv.FormatInt(p.Pricing.BaseAmount.Amount, 10)
}

func planBillingPeriod(p *plan.Plan) string {
	if p == nil || p.Pricing == nil {
		return ""
	}
	return string(p.Pricing.BillingPeriod)
}

func featureTypeDescription(ft plan.FeatureType) string {
	switch ft {
	case plan.FeatureBoolean:
		return "On/off feature toggle"
	case plan.FeatureSeat:
		return "Per-seat/user based feature"
	default:
		return "Usage-tracked feature with metering"
	}
}

func formatFeatureLimit(f plan.Feature) string {
	if f.Type == plan.FeatureBoolean {
		return ""
	}
	if f.Limit == 0 {
		return ""
	}
	return strconv.FormatInt(f.Limit, 10)
}

func hasFeatureKey(features []plan.Feature, key string) bool {
	for _, f := range features {
		if f.Key == key {
			return true
		}
	}
	return false
}

// metadataEntry is a key-value pair for iteration in templates.
type metadataEntry struct {
	Key   string
	Value string
}

func metadataEntries(m map[string]string) []metadataEntry {
	entries := make([]metadataEntry, 0, len(m))
	for k, v := range m {
		entries = append(entries, metadataEntry{Key: k, Value: v})
	}
	return entries
}

// featuresJSONValue returns the JSON string of the plan's features for the hidden input.
func featuresJSONValue(p *plan.Plan) string {
	if p == nil || len(p.Features) == 0 {
		return ""
	}
	type fj struct {
		Key       string `json:"key"`
		Name      string `json:"name"`
		Type      string `json:"type"`
		Limit     string `json:"limit"`
		Period    string `json:"period"`
		SoftLimit bool   `json:"soft_limit"`
	}
	items := make([]fj, len(p.Features))
	for i, f := range p.Features {
		items[i] = fj{
			Key:       f.Key,
			Name:      f.Name,
			Type:      string(f.Type),
			Limit:     strconv.FormatInt(f.Limit, 10),
			Period:    string(f.Period),
			SoftLimit: f.SoftLimit,
		}
	}
	b, _ := json.Marshal(items)
	return string(b)
}

// tiersJSONValue returns the JSON string of the plan's pricing tiers for the hidden input.
func tiersJSONValue(p *plan.Plan) string {
	if p == nil || p.Pricing == nil || len(p.Pricing.Tiers) == 0 {
		return ""
	}
	type tj struct {
		FeatureKey string `json:"feature_key"`
		Type       string `json:"type"`
		UpTo       string `json:"up_to"`
		UnitAmount string `json:"unit_amount"`
		FlatAmount string `json:"flat_amount"`
		Priority   string `json:"priority"`
	}
	items := make([]tj, len(p.Pricing.Tiers))
	for i, t := range p.Pricing.Tiers {
		items[i] = tj{
			FeatureKey: t.FeatureKey,
			Type:       string(t.Type),
			UpTo:       strconv.FormatInt(t.UpTo, 10),
			UnitAmount: strconv.FormatInt(t.UnitAmount.Amount, 10),
			FlatAmount: strconv.FormatInt(t.FlatAmount.Amount, 10),
			Priority:   strconv.Itoa(t.Priority),
		}
	}
	b, _ := json.Marshal(items)
	return string(b)
}

// metadataJSONValue returns the JSON string of the plan's metadata for the hidden input.
func metadataJSONValue(p *plan.Plan) string {
	if p == nil || len(p.Metadata) == 0 {
		return ""
	}
	type mj struct {
		Key   string `json:"key"`
		Value string `json:"value"`
	}
	items := make([]mj, 0, len(p.Metadata))
	for k, v := range p.Metadata {
		items = append(items, mj{Key: k, Value: v})
	}
	b, _ := json.Marshal(items)
	return string(b)
}

